import Foundation

// Define a logging function with different log levels
enum LogLevel: Int {
    case debug
    case info
    case warning
    case error
    
    var description: String {
        switch self {
        case .debug:
            return "Debug"
        case .info:
            return "Info"
        case .warning:
            return "Warning"
        case .error:
            return "Error"
        }
    }
}

func log(message: String, level: LogLevel = .info) {
    print("\(level.description): \(message)")
    // NSLog statements to capture detailed information
    #if DEBUG || RELEASE
    switch level {
    case .debug:
        NSLog("DEBUG: \(message)")
    case .info:
        NSLog("INFO: \(message)")
    case .warning:
        NSLog("WARNING: \(message)")
    case .error:
        NSLog("ERROR: \(message)")
    }
    #endif
}

// Tracking user interactions and app behavior
class Analytics {
    static func trackUserInteraction(event: String, userData: [String: Any] = [:]) {
        let message = "User Interaction: \(event) - User ID: \(userData["userId"] ?? "")"
        log(message: message)
        
        // Logging additional information about the user interaction
        if let userId = userData["userId"] as? String,
           let email = userData["email"] as? String {
            print("User ID: \(userId), Email Address: \(email)")
        }
    }
    
    static func trackApiCall(method: String, url: String, parameters: [String: Any] = [:], response: Any) {
        let message = "API Call: \(method) - URL: \(url)"
        log(message: message)
        
        // Logging additional information about the API call
        print("Request Payload: \(parameters)")
        if let statusCode = response as? Int,
           let statusMessage = response as? String {
            print("Status Code: \(statusCode), Status Message: \(statusMessage)")
        } else {
            print("Response Payload: \(response)")
        }
    }
    
    static func trackUserDataChange(userId: String, dataChanged: [String: Any] = [:]) {
        let message = "User Data Change - User ID: \(userId)"
        log(message: message)
        
        // Logging additional information about the user data change
        print("Data Changed: \(dataChanged)")
    }
    
    static func trackError(errorType: String, details: [String: Any] = [:]) {
        let message = "Error: \(errorType) - Details: \(details)"
        log(message: message)
        
        // Logging additional information about the error
        print("Error Details: \(details)")
    }
}

